if (finalStatus === 'answered' && !discordText && geminiExpected) {
  finalStatus = 'failed';
  failureReason = failureReason || 'empty_answer_text';
}

return [{
  json: {
    ...safeState,
    context_block: state.context_block || '',
    selected_context: state.selected_context || [],
    gemini_response_text: generatedText,
    discord_response_text: discordText,
    discord_response_character_count: discordText.length,
    model_refusal: modelRefusal,
    generation_failed: generationFailed,
    final_status: finalStatus,
    retrieval_status: retrievalStatus,
    response_status: 'not_posted',
    refusal_reason: refusalReason,
    failure_reason: failureReason,
    gemini_expected: geminiExpected,
    gemini_ran: geminiRan,
    rag_core_completed_ms: Date.now(),
    rag_core_workflow: 'RAG Core Execution - Phase 8'
  }
}];
